var e=[{id:`L2_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`여기는 알파. COM-1에서 침식파 발원지를 포착했습니다.`,JPN:`こちらアルファ。COM-1で侵食波発源地を捕捉しました。`,ENG:`Alpha here. COM-1 has eyes on the source of the Corruption Ray.`,TWN:`這裡是阿爾法。在COM-1探測到了侵蝕波的源頭。`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`데이터베이스에 따르면 원인은 제 3종 침식체의 고치로 추정됩니다.`,JPN:`データベースによると、原因は第3種侵食体の繭だと推定されます。`,ENG:`According to the database, it appears to come from a cocoon of Category 3 C.O.`,TWN:`根據資料庫推測，原因是3級侵蝕體的繭。`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`확인했습니다. 교전수칙에 의거. 침식억제기와 T3 중화기 투입. 즉시 소각절차에 들어갑니다.`,JPN:`確認しました。交戦規則に基づき、侵食抑制器とT3重火器投入。即時、焼却手続きに入ります。`,ENG:`Copy that. Based on the applicable ROE, deploy corruption suppressors and T3 heavy weapons to commence incineration.`,TWN:`已確認。根據交戰守則，投入侵蝕抑制器和T3級重火器，立即進行焚毀程序。`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`알겠습니다. 그럼 공격을......`,JPN:`わかりました。では攻撃を……`,ENG:`Wilco. Preparing to engage...`,TWN:`我知道了。那就攻擊……`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`엇?! 이 소리는......?`,JPN:`えっ！？この音は……？`,ENG:`Huh?! What's that sound?`,TWN:`呃？！這聲音是……？`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`PILOT_VOICE_NULL_NULL`,text:{KOREA:`급성 침식 반응 감지! 고치가 움직입니다!`,JPN:`急性侵食反応感知！　繭が動き出しました！`,ENG:`Acute Corruption response detected! The cocoon is moving!`,TWN:`偵測到急性侵蝕反應！繭動起來了！`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L11_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`이런! 타이밍이 안 좋긴 하지만 당황할 필요 없습니다.`,JPN:`しまった！　タイミングが悪いですが、慌てる必要はありません。`,ENG:`Dang it! This is bad timing, but there's no need to panic.`,TWN:`有這種事！雖然這個時機有點不妙，不過沒必要慌張。`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`분명 교전수칙에서도 이런 상황에 대응하는 매뉴얼이......`,JPN:`きっと交戦規則にもこういった状況に対応するマニュアルが……`,ENG:`I'm sure there's a standard operating procedure for this situation as well...`,TWN:`我記得交戰守則裡有寫，對應這種情況的指南……`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`매뉴얼은 됐어, 카일.`,JPN:`マニュアルはいい、カイル。`,ENG:`Forget about the procedure, Kyle.`,TWN:`不用查交戰守則了，凱爾。`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`JAKE_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`어차피 녀석이 깨어난 이상, 정면대결은 피할 수 없잖아?`,JPN:`どうせ奴が目覚めた以上、真っ向勝負は避けられないだろ？`,ENG:`We'll have no choice but to fight it head on now that it's awake.`,TWN:`反正那傢伙已經蘇醒了，正面交鋒是不可避免的吧？`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`JAKE_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`KYLE_DELTA_NULL_NULL`,text:{KOREA:`기다리십시오, 대령님. 항상 그런 식으로 무모하게 행동하시는 건......!`,JPN:`待ってください、大佐。いつもそんなふうにむやみに行動されては……！`,ENG:`Wait, Colonel. That sounds too reckless!`,TWN:`請等一下，上校。您總是這樣魯莽行動……！`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`KYLE_DELTA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`카일, 완벽한 계획을 세우는 것도 좋지만.....`,JPN:`カイル、完璧な計画を立てることもいいが……`,ENG:`Kyle, as nice it would be to have a perfect plan...`,TWN:`凱爾，制定完美的計畫是很不錯……`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`JAKE_DELTA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JAKE_DELTA_NULL_NULL`,text:{KOREA:`......망설이다 후회했을 땐 늦는 법이라고.`,JPN:`……ためらって後悔した時には遅いんだよ。`,ENG:`It'll be too late if we hesitate.`,TWN:`……但猶豫就會後悔，那樣就太遲了。`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`JAKE_DELTA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`저, 저거 침식체야? 저렇게 큰 건 들어본 적도 없어!`,JPN:`あ、あれが侵食体！？　あんなに大きいのは見たこともない！`,ENG:`I-is that a C.O.? I've never even heard of anything that big!`,TWN:`那、那是侵蝕體嗎？我可沒聽過有這麼大的侵蝕體！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`모두 도망쳐!`,JPN:`みんな、逃げて！`,ENG:`Run, everyone!`,TWN:`大家快逃！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`GIRL_EXTRA_NULL_NULL`,text:{KOREA:`으윽! 나, 나 다리가 끼어서 안 움직여!`,JPN:`ううっ！　わ、私、足が挟まって動けないよ！`,ENG:`Eek! M-my leg is stuck! I can't move!`,TWN:`呃呃！我，我的腿被夾住了，動不了！`},stage:{bg:`CITY_STREET_DISASTER`,slots:{L:null,C:null,R:null}}}];export{e as default};